/* ------------ HUD building ------------ */
function thumbUrl(item, small){
  let url = item.url || '';
  if(small && url.includes('unsplash.com')){
    url = url.replace(/w=\d+/, 'w=400').replace(/q=\d+/, 'q=60');
  }
  return url;
}
function thumbHtml(item, small){
  const isUser = item.id && item.id.startsWith('user-');
  const bg = item.kind==='video'
    ? `background:#111`
    : `background-image:url('${thumbUrl(item, small)}');background-size:cover;background-position:center`;
  const action = item.type === 'cinema' ? `cinema-media:${item.id}` : `scene:${item.id}`;
  const typeTag = item.type === 'cinema' ? '<span style="position:absolute;right:6px;bottom:6px;font-size:8px;background:rgba(0,0,0,.55);padding:1px 5px;border-radius:4px">📺</span>' : '';
  const delBtn = isUser
    ? `<div class="thumb-del" data-gaze data-action="deleteMedia:${item.id}" style="position:absolute;top:4px;right:4px;width:22px;height:22px;border-radius:50%;background:rgba(220,50,50,.7);color:#fff;font-size:12px;display:flex;align-items:center;justify-content:center;cursor:pointer;z-index:2">🗑</div>`
    : '';
  return `<div class="thumb glass-soft" data-gaze data-action="${action}" style="${bg}">
            ${delBtn}
            <div class="lbl">${item.name}</div>${typeTag}
          </div>`;
}

